import { GoogleGenAI } from "@google/genai";
import { Project, AIModuleConfig } from "../types";

export async function generateAIContent(
  config: AIModuleConfig,
  project: Project,
  userInputs: Record<string, string>
): Promise<string> {
  const apiKey = process.env.API_KEY;
  if (!apiKey) throw new Error("API Key is missing. Please check your environment configuration.");

  const ai = new GoogleGenAI({ apiKey });

  // Prepare the prompt by replacing placeholders
  let finalPrompt = config.prompt
    .replace('{style}', project.style)
    .replace('{coupleNames}', project.coupleNames)
    .replace('{location}', project.location);

  // Append user-provided inputs
  const inputContext = Object.entries(userInputs)
    .map(([key, value]) => `${key.toUpperCase()}: ${value}`)
    .join('\n');

  const fullPrompt = `
    Context:
    Wedding Couple: ${project.coupleNames}
    Wedding Date: ${project.weddingDate}
    Style: ${project.style}
    Location: ${project.location}

    User Specific Inputs:
    ${inputContext}

    Task:
    ${finalPrompt}

    Format the output in clean Markdown. Be detailed, professional, and creative.
  `;

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: fullPrompt,
    });

    return response.text || "No response generated.";
  } catch (error) {
    console.error("Gemini API Error:", error);
    throw error;
  }
}

import React, { useState, useEffect } from 'react';
import { 
  LayoutDashboard, 
  FolderKanban, 
  Sparkles, 
  Settings as SettingsIcon,
  Plus,
  LogOut,
  Calendar,
  AlertCircle,
  Menu,
  X,
  ChevronRight
} from 'lucide-react';
import { Project, AIModuleType, UserProfile } from './types';
import Dashboard from './pages/Dashboard';
import ProjectList from './pages/ProjectList';
import ProjectDetail from './pages/ProjectDetail';
import AIStudio from './pages/AIStudio';
import Settings from './pages/Settings';

