  const [activeTab, setActiveTab] = useState<'dashboard' | 'projects' | 'ai-studio' | 'settings'>('dashboard');
  const [selectedProjectId, setSelectedProjectId] = useState<string | null>(null);
  const [selectedModuleId, setSelectedModuleId] = useState<AIModuleType | null>(null);
  const [isSidebarOpen, setIsSidebarOpen] = useState(true);

  const [projects, setProjects] = useState<Project[]>(() => {
    const saved = localStorage.getItem('wedding_projects');
    return saved ? JSON.parse(saved) : [
      {
        id: '1',
        coupleNames: 'Alex & Maria',
        weddingDate: new Date(Date.now() + 15 * 24 * 60 * 60 * 1000).toISOString().split('T')[0],
        location: 'Athens Riviera',
        style: 'Cinematic',
        status: 'booked',
        notes: 'Classic elegant wedding by the sea.',
        contact: { email: 'maria@example.com', phone: '+30 6900000000', whatsapp: '306900000000' },
        payments: { packageName: 'Gold Package', totalAmount: 2500, depositPaid: true, balancePaid: false },
        deliverables: { highlightFilm: true, fullFilm: true, socialMediaContent: true, usbBox: false, onlineLink: true },
        deadline: new Date(Date.now() + 60 * 24 * 60 * 60 * 1000).toISOString().split('T')[0],
        createdAt: new Date().toISOString()
      }
    ];
  });

  const [userProfile, setUserProfile] = useState<UserProfile>(() => {
    const saved = localStorage.getItem('user_profile');
    return saved ? JSON.parse(saved) : {
      fullName: 'John Videographer',
      businessName: 'Lumina Wedding Films',
      email: 'john@lumina.pro',
      phone: '+30 2101234567',
      website: 'www.luminafilms.pro',
      address: 'Vouliagmenis 123, Athens',
      brandColors: { primary: '#6366f1', secondary: '#a855f7', accent: '#ec4899' },
      contractTemplate: 'Default wedding videography contract template text goes here...'
    };
  });

  useEffect(() => {
    localStorage.setItem('wedding_projects', JSON.stringify(projects));
  }, [projects]);

  useEffect(() => {
    localStorage.setItem('user_profile', JSON.stringify(userProfile));
  }, [userProfile]);

  const navigateToProject = (id: string) => {
    setSelectedProjectId(id);
    setActiveTab('projects');
  };

  const navigateToAIModule = (moduleId: AIModuleType, projectId?: string) => {
    setSelectedModuleId(moduleId);
    if (projectId) setSelectedProjectId(projectId);
    setActiveTab('ai-studio');
