              <SidebarItem icon={LayoutDashboard} label="Dashboard" tab="dashboard" />
              <SidebarItem icon={FolderKanban} label="Projects" tab="projects" />
              <SidebarItem icon={Sparkles} label="AI Studio" tab="ai-studio" />
              <SidebarItem icon={SettingsIcon} label="Settings" tab="settings" />
