            <div className="flex items-center gap-3 p-3 rounded-xl bg-slate-800/30">
              <div className="w-8 h-8 rounded-full bg-slate-700 flex items-center justify-center text-xs">
                {userProfile.fullName.charAt(0)}
              </div>
              <div className="flex-1 min-w-0">
                <p className="text-sm font-medium text-white truncate">{userProfile.fullName}</p>
                <p className="text-xs text-slate-500 truncate">{userProfile.businessName}</p>
              </div>
              <button className="text-slate-500 hover:text-rose-400 transition-colors">
