            <Dashboard 
              projects={projects} 
              onNavigateProject={navigateToProject} 
              onNavigateAI={navigateToAIModule}
            />
          )}
          {activeTab === 'projects' && !selectedProjectId && (
            <ProjectList 
              projects={projects} 
              onSelectProject={setSelectedProjectId}
              onAddProject={(p) => setProjects([...projects, p])}
            />
          )}
          {activeTab === 'projects' && selectedProjectId && (
            <ProjectDetail 
              project={projects.find(p => p.id === selectedProjectId)!}
              onUpdateProject={(updated) => setProjects(projects.map(p => p.id === updated.id ? updated : p))}
              onDeleteProject={(id) => {
                setProjects(projects.filter(p => p.id !== id));
                setSelectedProjectId(null);
              }}
              onBack={() => setSelectedProjectId(null)}
              onNavigateAI={(mid) => navigateToAIModule(mid, selectedProjectId)}
