          )}
          {activeTab === 'ai-studio' && (
            <AIStudio 
              projects={projects}
              initialProjectId={selectedProjectId}
              initialModuleId={selectedModuleId}
            />
          )}
          {activeTab === 'settings' && (
            <Settings 
              profile={userProfile} 
              onUpdateProfile={setUserProfile} 
            />
          )}
        </div>
      </main>
    </div>
  );
};

export default App;

import React from 'react';
import { Project, AIModuleType } from '../types';
import { Calendar, Users, FileText, CheckCircle2, ChevronRight, Clock, Sparkles } from 'lucide-react';
import { AI_MODULES, STATUS_COLORS } from '../constants';

interface DashboardProps {
  projects: Project[];
  onNavigateProject: (id: string) => void;
  onNavigateAI: (moduleId: AIModuleType) => void;
}

const Dashboard: React.FC<DashboardProps> = ({ projects, onNavigateProject, onNavigateAI }) => {
  const upcoming = [...projects]
    .sort((a, b) => new Date(a.weddingDate).getTime() - new Date(b.weddingDate).getTime())
    .slice(0, 3);

  const getUrgencyColor = (dateStr: string) => {
    const diff = (new Date(dateStr).getTime() - Date.now()) / (1000 * 60 * 60 * 24);
    if (diff < 7) return 'text-rose-400 border-rose-500/30 bg-rose-500/10';
    if (diff < 30) return 'text-amber-400 border-amber-500/30 bg-amber-500/10';
    return 'text-sky-400 border-sky-500/30 bg-sky-500/10';
  };

  return (
    <div className="space-y-8 animate-in fade-in duration-500">
      <header>
        <h2 className="text-3xl font-bold font-serif mb-2">Welcome Back!</h2>
        <p className="text-slate-400">Here is what is happening with your studio today.</p>
      </header>

      {/* Quick Stats */}
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-4">
        <StatCard icon={Calendar} label="Active Projects" value={projects.length.toString()} color="text-indigo-400" />
        <StatCard icon={Users} label="Total Bookings" value={projects.filter(p => p.status === 'booked').length.toString()} color="text-sky-400" />
        <StatCard icon={FileText} label="Editing Phase" value={projects.filter(p => p.status === 'editing').length.toString()} color="text-amber-400" />
        <StatCard icon={CheckCircle2} label="Delivered" value={projects.filter(p => p.status === 'delivered').length.toString()} color="text-emerald-400" />
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
        {/* Timeline */}
        <div className="lg:col-span-2 space-y-4">
          <div className="flex items-center justify-between mb-4">
            <h3 className="text-xl font-bold font-serif flex items-center gap-2">
              <Clock className="text-indigo-400" size={24} />
              Upcoming Weddings
            </h3>
            <button className="text-sm text-indigo-400 hover:text-indigo-300 font-medium transition-colors">View All</button>
          </div>
          <div className="space-y-4">
            {upcoming.map(project => (
              <div 
                key={project.id}
                onClick={() => onNavigateProject(project.id)}
                className="glass p-5 rounded-2xl flex flex-col md:flex-row md:items-center justify-between gap-4 cursor-pointer hover:bg-slate-800/40 transition-all border border-transparent hover:border-slate-700"
              >
                <div className="flex items-center gap-4">
                  <div className={`w-14 h-14 rounded-xl flex flex-col items-center justify-center border font-bold ${getUrgencyColor(project.weddingDate)}`}>
                    <span className="text-xs uppercase tracking-tighter opacity-80">
                      {new Date(project.weddingDate).toLocaleString('default', { month: 'short' })}
                    </span>
                    <span className="text-xl">
                      {new Date(project.weddingDate).getDate()}
                    </span>
                  </div>
                  <div>
                    <h4 className="font-bold text-lg">{project.coupleNames}</h4>
                    <p className="text-slate-400 text-sm">{project.location} • {project.style}</p>
                  </div>
                </div>
                <div className="flex items-center gap-3">
                  <span className={`px-3 py-1 rounded-full text-xs font-semibold border ${STATUS_COLORS[project.status]}`}>
                    {project.status.replace('_', ' ').toUpperCase()}
                  </span>
                  <ChevronRight className="text-slate-600" size={20} />
                </div>
              </div>
            ))}
          </div>
        </div>

        {/* AI Quick Access */}
        <div className="space-y-4">
          <h3 className="text-xl font-bold font-serif flex items-center gap-2">
            <Sparkles className="text-purple-400" size={24} />
            AI Modules
          </h3>
          <div className="grid grid-cols-1 gap-2">
            {AI_MODULES.slice(0, 6).map(module => (
              <button
                key={module.id}
                onClick={() => onNavigateAI(module.id)}
                className="glass-dark p-3 rounded-xl flex items-center gap-3 hover:bg-slate-700/40 transition-all text-left group border border-slate-800/50 hover:border-indigo-500/50"
              >
                <span className="text-2xl">{module.icon}</span>
                <div className="flex-1">
                  <p className="text-sm font-semibold">{module.title}</p>
                  <p className="text-xs text-slate-500 line-clamp-1">{module.description}</p>
                </div>
                <ChevronRight size={16} className="text-slate-600 group-hover:text-white transition-colors" />
              </button>
            ))}
          </div>
        </div>
      </div>
    </div>
  );
};

