                    onChange={e => setEditedProject({...editedProject, coupleNames: e.target.value})}
                  />
                ) : (
                  <h2 className="text-4xl font-bold font-serif">{project.coupleNames}</h2>
                )}
                <div className="flex items-center gap-4 mt-4 text-slate-400">
                  <span className="flex items-center gap-1.5"><Calendar size={18} /> {new Date(project.weddingDate).toLocaleDateString()}</span>
                  <span className="flex items-center gap-1.5"><MapPin size={18} /> {project.location}</span>
                </div>
              </div>
              <div className="bg-slate-900/50 p-4 rounded-2xl border border-slate-800">
