                      </div>
                      <span className={`text-xs font-medium ${project.payments.depositPaid ? 'text-emerald-400' : 'text-slate-500'}`}>Deposit</span>
                    </label>
                    <label className="flex items-center gap-2 cursor-pointer group">
                      <div 
                        onClick={() => togglePayment('balancePaid')}
                        className={`w-5 h-5 rounded flex items-center justify-center border transition-all ${project.payments.balancePaid ? 'bg-emerald-500 border-emerald-500' : 'border-slate-700 group-hover:border-emerald-500/50'}`}
                      >
                        {project.payments.balancePaid && <CheckCircle size={14} className="text-white" />}
