import React, { useState, useEffect } from 'react';
import { Project, AIModuleType, AIResult } from '../types';
import { Sparkles, Send, Loader2, Save, Trash2, History, ChevronDown, Check, ExternalLink } from 'lucide-react';
import { AI_MODULES } from '../constants';
import { generateAIContent } from '../services/geminiService';

interface AIStudioProps {
  projects: Project[];
  initialProjectId?: string | null;
  initialModuleId?: AIModuleType | null;
}

const AIStudio: React.FC<AIStudioProps> = ({ projects, initialProjectId, initialModuleId }) => {
  const [selectedProjectId, setSelectedProjectId] = useState<string>(initialProjectId || (projects[0]?.id || ''));
  const [selectedModuleId, setSelectedModuleId] = useState<AIModuleType>(initialModuleId || 'shot-planning');
  const [inputs, setInputs] = useState<Record<string, string>>({});
  const [isGenerating, setIsGenerating] = useState(false);
  const [result, setResult] = useState<string | null>(null);
  const [savedResults, setSavedResults] = useState<AIResult[]>(() => {
    const saved = localStorage.getItem('ai_results');
    return saved ? JSON.parse(saved) : [];
  });

  const selectedProject = projects.find(p => p.id === selectedProjectId);
  const selectedModule = AI_MODULES.find(m => m.id === selectedModuleId)!;

  useEffect(() => {
    if (initialProjectId) setSelectedProjectId(initialProjectId);
    if (initialModuleId) setSelectedModuleId(initialModuleId);
  }, [initialProjectId, initialModuleId]);

  useEffect(() => {
    localStorage.setItem('ai_results', JSON.stringify(savedResults));
  }, [savedResults]);

  const handleGenerate = async () => {
    if (!selectedProject) return;
    setIsGenerating(true);
    setResult(null);
    try {
      const output = await generateAIContent(selectedModule, selectedProject, inputs);
      setResult(output);
    } catch (err) {
      alert("Failed to generate content. Please check console for details.");
    } finally {
      setIsGenerating(false);
    }
  };

  const handleSave = () => {
    if (!result || !selectedProject) return;
    const newResult: AIResult = {
      id: Date.now().toString(),
      projectId: selectedProjectId,
      moduleType: selectedModuleId,
      title: `${selectedModule.title} for ${selectedProject.coupleNames}`,
      content: result,
      createdAt: new Date().toISOString()
    };
    setSavedResults([newResult, ...savedResults]);
    alert("Saved to Project Results!");
  };

  return (
    <div className="space-y-8 animate-in fade-in duration-500">
      <header>
        <h2 className="text-3xl font-bold font-serif mb-2">AI Studio</h2>
        <p className="text-slate-400">Transform your creative workflow with professional AI assistance.</p>
      </header>

      <div className="grid grid-cols-1 lg:grid-cols-12 gap-8">
        {/* Sidebar Selector */}
        <div className="lg:col-span-3 space-y-6">
          <div className="glass p-4 rounded-2xl space-y-4">
            <h3 className="text-sm font-bold text-slate-500 uppercase tracking-widest px-2">Module</h3>
            <div className="space-y-1">
              {AI_MODULES.map(module => (
                <button
                  key={module.id}
                  onClick={() => {
                    setSelectedModuleId(module.id);
                    setResult(null);
                    setInputs({});
                  }}
                  className={`w-full flex items-center gap-3 px-4 py-3 rounded-xl transition-all ${
                    selectedModuleId === module.id ? 'bg-indigo-600/20 text-indigo-400 ring-1 ring-indigo-500/50' : 'text-slate-400 hover:text-white hover:bg-slate-800/50'
                  }`}
                >
                  <span className="text-xl">{module.icon}</span>
                  <span className="text-sm font-semibold truncate">{module.title}</span>
                </button>
              ))}
            </div>
          </div>
        </div>

        {/* Workspace */}
        <div className="lg:col-span-6 space-y-6">
          <div className="glass p-8 rounded-3xl space-y-8">
            <div className="flex flex-col md:flex-row gap-6">
              <div className="flex-1 space-y-2">
                <label className="text-xs font-bold text-slate-500 uppercase tracking-widest">Select Project</label>
                <div className="relative">
                  <select 
                    value={selectedProjectId}
                    onChange={(e) => setSelectedProjectId(e.target.value)}
                    className="w-full glass-dark p-4 rounded-2xl appearance-none outline-none focus:ring-2 focus:ring-indigo-500/50 pr-12 font-bold"
                  >
                    {projects.map(p => (
                      <option key={p.id} value={p.id}>{p.coupleNames} ({new Date(p.weddingDate).getFullYear()})</option>
                    ))}
                  </select>
                  <ChevronDown className="absolute right-4 top-1/2 -translate-y-1/2 text-slate-500 pointer-events-none" size={20} />
                </div>
              </div>
            </div>

            <div className="space-y-6">
              <div className="flex items-center gap-4">
                <div className="w-12 h-12 rounded-2xl bg-indigo-500/20 flex items-center justify-center text-2xl border border-indigo-500/30">
                  {selectedModule.icon}
                </div>
                <div>
                  <h3 className="text-xl font-bold">{selectedModule.title}</h3>
                  <p className="text-slate-500 text-sm">{selectedModule.description}</p>
                </div>
              </div>

              <div className="grid grid-cols-1 gap-4">
                {selectedModule.inputs.map(input => (
                  <div key={input.key} className="space-y-2">
                    <label className="text-sm font-medium text-slate-400">{input.label}</label>
                    {input.type === 'textarea' ? (
                      <textarea
                        value={inputs[input.key] || ''}
                        onChange={e => setInputs({...inputs, [input.key]: e.target.value})}
                        className="w-full glass-dark p-4 rounded-2xl min-h-[100px] outline-none focus:ring-1 focus:ring-indigo-500"
                        placeholder="Add specific details to guide the AI..."
                      />
                    ) : input.type === 'select' ? (
                      <select
                        value={inputs[input.key] || ''}
                        onChange={e => setInputs({...inputs, [input.key]: e.target.value})}
                        className="w-full glass-dark p-4 rounded-2xl outline-none focus:ring-1 focus:ring-indigo-500"
                      >
                        <option value="">Select an option...</option>
                        {input.options?.map(opt => <option key={opt} value={opt}>{opt}</option>)}
                      </select>
                    ) : (
                      <input
                        type="text"
                        value={inputs[input.key] || ''}
                        onChange={e => setInputs({...inputs, [input.key]: e.target.value})}
                        className="w-full glass-dark p-4 rounded-2xl outline-none focus:ring-1 focus:ring-indigo-500"
                        placeholder="Type here..."
                      />
                    )}
                  </div>
                ))}
              </div>

              <button 
                onClick={handleGenerate}
                disabled={isGenerating || !selectedProjectId}
                className="w-full py-4 rounded-2xl bg-gradient-to-r from-indigo-600 to-purple-600 hover:from-indigo-500 hover:to-purple-500 text-white font-bold flex items-center justify-center gap-3 transition-all disabled:opacity-50 disabled:cursor-not-allowed shadow-xl shadow-indigo-600/20"
              >
                {isGenerating ? (
                  <>
                    <Loader2 className="animate-spin" size={20} />
                    Generating your magic...
                  </>
                ) : (
                  <>
                    <Sparkles size={20} />
                    Generate Content
                  </>
                )}
              </button>
            </div>
          </div>

          {result && (
            <div className="glass p-8 rounded-3xl space-y-6 animate-in slide-in-from-bottom-4">
              <div className="flex items-center justify-between border-b border-slate-800 pb-4">
                <h4 className="text-lg font-bold flex items-center gap-2"><Check className="text-emerald-400" /> AI Generated Result</h4>
                <div className="flex gap-2">
                  <button onClick={handleSave} className="flex items-center gap-2 px-4 py-2 bg-emerald-600/20 text-emerald-400 border border-emerald-500/30 rounded-xl hover:bg-emerald-600 transition-all hover:text-white">
                    <Save size={18} /> Save Result
                  </button>
                </div>
              </div>
              <div className="prose prose-invert max-w-none text-slate-300 whitespace-pre-wrap leading-relaxed">
                {result}
              </div>
            </div>
          )}
        </div>

        {/* History / Saved */}
        <div className="lg:col-span-3 space-y-6">
          <div className="glass p-6 rounded-3xl space-y-6">
            <h3 className="text-lg font-bold flex items-center gap-2"><History size={20} className="text-sky-400" /> Recent Results</h3>
            <div className="space-y-4">
              {savedResults.length === 0 ? (
                <p className="text-xs text-slate-500 text-center py-8">No results saved yet.</p>
              ) : (
                savedResults.filter(r => r.projectId === selectedProjectId).map(result => (
                  <div key={result.id} className="group glass-dark p-4 rounded-xl border border-slate-800 hover:border-slate-600 transition-all">
                    <div className="flex items-start justify-between">
                      <div className="flex-1">
                        <p className="text-xs font-bold text-indigo-400 mb-1">{result.moduleType.replace('-', ' ').toUpperCase()}</p>
                        <p className="text-sm font-semibold truncate text-white">{new Date(result.createdAt).toLocaleDateString()}</p>
                      </div>
                      <button 
                        onClick={() => setSavedResults(savedResults.filter(r => r.id !== result.id))}
                        className="text-slate-600 hover:text-rose-400 p-1 opacity-0 group-hover:opacity-100 transition-opacity"
                      >
                        <Trash2 size={14} />
                      </button>
                    </div>
                    <button 
                      onClick={() => setResult(result.content)}
                      className="mt-3 text-xs text-slate-400 flex items-center gap-1 hover:text-white"
                    >
                      <ExternalLink size={12} /> View Details
                    </button>
                  </div>
                ))
              )}
            </div>
          </div>
        </div>
      </div>
    </div>
  );
};

