interface ProjectDetailProps {
  project: Project;
  onUpdateProject: (p: Project) => void;
  onDeleteProject: (id: string) => void;
  onBack: () => void;
  onNavigateAI: (moduleId: AIModuleType) => void;
}

const ProjectDetail: React.FC<ProjectDetailProps> = ({ 
  project, onUpdateProject, onDeleteProject, onBack, onNavigateAI 
}) => {
  const [isEditing, setIsEditing] = useState(false);
  const [editedProject, setEditedProject] = useState<Project>(project);

  const handleSave = () => {
    onUpdateProject(editedProject);
    setIsEditing(false);
  };

  const toggleDeliverable = (key: keyof Project['deliverables']) => {
    const updated = {
      ...project,
      deliverables: { ...project.deliverables, [key]: !project.deliverables[key] }
    };
    onUpdateProject(updated);
  };

  const togglePayment = (key: 'depositPaid' | 'balancePaid') => {
    const updated = {
      ...project,
      payments: { ...project.payments, [key]: !project.payments[key] }
    };
    onUpdateProject(updated);
  };

  const getDaysRemaining = () => {
    const diff = new Date(project.weddingDate).getTime() - Date.now();
    return Math.ceil(diff / (1000 * 60 * 60 * 24));
  };

  return (
    <div className="space-y-8 animate-in slide-in-from-right-4 duration-500">
      <div className="flex items-center justify-between">
        <button onClick={onBack} className="flex items-center gap-2 text-slate-400 hover:text-white transition-colors">
          <ArrowLeft size={20} />
          Back to Projects
        </button>
        <div className="flex gap-2">
          {isEditing ? (
            <>
              <button onClick={handleSave} className="flex items-center gap-2 bg-emerald-600 hover:bg-emerald-500 px-4 py-2 rounded-lg font-bold transition-all">
                <Save size={18} /> Save
              </button>
              <button onClick={() => setIsEditing(false)} className="flex items-center gap-2 bg-slate-700 hover:bg-slate-600 px-4 py-2 rounded-lg font-bold transition-all text-slate-200">
                <X size={18} /> Cancel
              </button>
            </>
          ) : (
            <>
              <button onClick={() => setIsEditing(true)} className="p-2 glass text-slate-400 hover:text-white rounded-lg transition-colors">
                <Edit2 size={18} />
              </button>
              <button onClick={() => onDeleteProject(project.id)} className="p-2 glass text-slate-400 hover:text-rose-400 rounded-lg transition-colors">
                <Trash2 size={18} />
              </button>
            </>
          )}
        </div>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
        {/* Left Column: Info & Status */}
        <div className="lg:col-span-2 space-y-8">
