                  <span className="text-3xl">{module.icon}</span>
                  <span className="text-xs font-bold text-center tracking-tight text-slate-300">{module.title}</span>
                </button>
              ))}
            </div>
          </section>
        </div>

        {/* Right Column: Checklist & Notes */}
        <div className="space-y-8">
          <section className="glass p-6 rounded-3xl space-y-6">
            <h3 className="text-lg font-bold flex items-center gap-2"><ListChecks size={20} className="text-sky-400" /> Deliverables</h3>
            <div className="space-y-3">
              {/* Fixed type safety issues for Deliverables mapping by casting key to string and Deliverables keyof union */}
              {(Object.keys(project.deliverables) as (keyof typeof project.deliverables)[]).map((key) => {
                const deliverableKey = key as keyof typeof project.deliverables;
                return (
                  <div 
                    key={String(deliverableKey)}
                    onClick={() => toggleDeliverable(deliverableKey)}
                    className={`flex items-center justify-between p-4 rounded-xl border cursor-pointer transition-all ${project.deliverables[deliverableKey] ? 'bg-indigo-500/10 border-indigo-500/30 text-indigo-400' : 'bg-slate-900/30 border-slate-800 text-slate-500'}`}
