                  </div>
                );
              })}
            </div>
          </section>

          <section className="glass p-6 rounded-3xl space-y-4">
            <h3 className="text-lg font-bold flex items-center gap-2"><FileText size={20} className="text-amber-400" /> Project Notes</h3>
