      <main className="flex-1 flex flex-col min-h-screen relative overflow-x-hidden">
        {/* Mobile Header */}
        <header className="md:hidden glass p-4 flex items-center justify-between sticky top-0 z-40">
          <button onClick={() => setIsSidebarOpen(true)} className="p-2 text-slate-400">
             <Menu size={24} />
          </button>
          <span className="font-serif font-bold text-lg gradient-text">WeddingFilmAI</span>
          <div className="w-10 h-10 rounded-full bg-slate-800 flex items-center justify-center text-xs">
            {userProfile.fullName.charAt(0)}
          </div>
        </header>

        <div className="p-4 md:p-8 flex-1 max-w-7xl mx-auto w-full">
          {activeTab === 'dashboard' && (
            <Dashboard 
              projects={projects} 
              onNavigateProject={navigateToProject} 
              onNavigateAI={navigateToAIModule}
            />
          )}
          {activeTab === 'projects' && !selectedProjectId && (
            <ProjectList 
              projects={projects} 
              onSelectProject={setSelectedProjectId}
              onAddProject={(p) => setProjects([...projects, p])}
            />
          )}
          {activeTab === 'projects' && selectedProjectId && (
            <ProjectDetail 
              project={projects.find(p => p.id === selectedProjectId)!}
              onUpdateProject={(updated) => setProjects(projects.map(p => p.id === updated.id ? updated : p))}
              onDeleteProject={(id) => {
                if (confirm('Είστε σίγουροι ότι θέλετε να διαγράψετε αυτό το έργο;')) {
                  setProjects(projects.filter(p => p.id !== id));
                  setSelectedProjectId(null);
                }
              }}
              onBack={() => setSelectedProjectId(null)}
              onNavigateAI={(mid) => navigateToAIModule(mid, selectedProjectId)}
            />
          )}
          {activeTab === 'ai-studio' && (
            <AIStudio 
              projects={projects}
              initialProjectId={selectedProjectId}
              initialModuleId={selectedModuleId}
            />
          )}
          {activeTab === 'settings' && (
            <Settings 
              profile={userProfile} 
              onUpdateProfile={setUserProfile} 
            />
          )}
        </div>
      </main>
    </div>
  );
};

export default App;

