import React, { useState, useEffect } from 'react';
import { Project, AIModuleType, AIResult } from '../types';
import { Sparkles, Send, Loader2, Save, Trash2, History, ChevronDown, Check, ExternalLink, Menu } from 'lucide-react';
import { AI_MODULES } from '../constants';
import { generateAIContent } from '../services/geminiService';

interface AIStudioProps {
  projects: Project[];
  initialProjectId?: string | null;
  initialModuleId?: AIModuleType | null;
}

const AIStudio: React.FC<AIStudioProps> = ({ projects, initialProjectId, initialModuleId }) => {
  const [selectedProjectId, setSelectedProjectId] = useState<string>(initialProjectId || (projects[0]?.id || ''));
  const [selectedModuleId, setSelectedModuleId] = useState<AIModuleType>(initialModuleId || 'shot-planning');
  const [inputs, setInputs] = useState<Record<string, string>>({});
  const [isGenerating, setIsGenerating] = useState(false);
  const [result, setResult] = useState<string | null>(null);
  const [isModuleSelectorOpen, setIsModuleSelectorOpen] = useState(false);
  const [savedResults, setSavedResults] = useState<AIResult[]>(() => {
    const saved = localStorage.getItem('ai_results');
    return saved ? JSON.parse(saved) : [];
  });

  const selectedProject = projects.find(p => p.id === selectedProjectId);
  const selectedModule = AI_MODULES.find(m => m.id === selectedModuleId)!;

  useEffect(() => {
    if (initialProjectId) setSelectedProjectId(initialProjectId);
    if (initialModuleId) setSelectedModuleId(initialModuleId);
  }, [initialProjectId, initialModuleId]);

  useEffect(() => {
    localStorage.setItem('ai_results', JSON.stringify(savedResults));
  }, [savedResults]);

  const handleGenerate = async () => {
    if (!selectedProject) return;
    setIsGenerating(true);
    setResult(null);
    try {
      const output = await generateAIContent(selectedModule, selectedProject, inputs);
      setResult(output);
    } catch (err) {
      alert("Αποτυχία παραγωγής περιεχομένου. Παρακαλώ ελέγξτε τις ρυθμίσεις σας.");
    } finally {
      setIsGenerating(false);
    }
  };

  const handleSave = () => {
    if (!result || !selectedProject) return;
    const newResult: AIResult = {
      id: Date.now().toString(),
      projectId: selectedProjectId,
      moduleType: selectedModuleId,
      title: `${selectedModule.title} για ${selectedProject.coupleNames}`,
      content: result,
      createdAt: new Date().toISOString()
    };
    setSavedResults([newResult, ...savedResults]);
    alert("Αποθηκεύτηκε στα Αποτελέσματα του Έργου!");
  };

  return (
    <div className="space-y-8 animate-in fade-in duration-500">
      <header>
        <h2 className="text-3xl font-bold font-serif mb-2">AI Studio</h2>
        <p className="text-slate-400">Μεταμορφώστε τη δημιουργική σας ροή με επαγγελματική τεχνητή νοημοσύνη.</p>
      </header>

      <div className="grid grid-cols-1 lg:grid-cols-12 gap-6 md:gap-8">
        {/* Module Selection for Mobile */}
        <div className="lg:hidden">
          <button 
            onClick={() => setIsModuleSelectorOpen(!isModuleSelectorOpen)}
            className="w-full glass p-5 rounded-2xl flex items-center justify-between border-2 border-indigo-500/30"
          >
            <div className="flex items-center gap-3">
              <span className="text-3xl">{selectedModule.icon}</span>
              <span className="font-bold text-lg">{selectedModule.title}</span>
            </div>
            <ChevronDown size={24} className={`transition-transform ${isModuleSelectorOpen ? 'rotate-180' : ''}`} />
          </button>

          {isModuleSelectorOpen && (
            <div className="mt-2 glass p-4 rounded-2xl grid grid-cols-1 gap-2 animate-in slide-in-from-top-2">
              {AI_MODULES.map(module => (
                <button
                  key={module.id}
                  onClick={() => {
                    setSelectedModuleId(module.id);
                    setIsModuleSelectorOpen(false);
                    setResult(null);
                    setInputs({});
                  }}
                  className={`w-full flex items-center gap-4 px-4 py-4 rounded-xl transition-all ${
                    selectedModuleId === module.id ? 'bg-indigo-600 text-white' : 'text-slate-400 hover:bg-slate-800'
                  }`}
                >
                  <span className="text-2xl">{module.icon}</span>
                  <span className="font-bold">{module.title}</span>
                </button>
              ))}
            </div>
          )}
        </div>

        {/* Sidebar Selector (Desktop Only) */}
        <div className="hidden lg:block lg:col-span-3 space-y-6">
          <div className="glass p-4 rounded-2xl space-y-4">
            <h3 className="text-xs font-bold text-slate-500 uppercase tracking-widest px-2">Επιλέξτε Εργαλείο</h3>
            <div className="space-y-1">
              {AI_MODULES.map(module => (
                <button
                  key={module.id}
                  onClick={() => {
                    setSelectedModuleId(module.id);
                    setResult(null);
                    setInputs({});
                  }}
                  className={`w-full flex items-center gap-3 px-4 py-3.5 rounded-xl transition-all ${
                    selectedModuleId === module.id ? 'bg-indigo-600/20 text-indigo-400 ring-1 ring-indigo-500/50' : 'text-slate-400 hover:text-white hover:bg-slate-800/50'
                  }`}
                >
                  <span className="text-xl shrink-0">{module.icon}</span>
                  <span className="text-sm font-bold truncate">{module.title}</span>
                </button>
              ))}
            </div>
          </div>
        </div>

        {/* Workspace */}
        <div className="lg:col-span-6 space-y-6">
          <div className="glass p-6 md:p-8 rounded-3xl space-y-8">
            <div className="flex flex-col gap-6">
              <div className="space-y-2">
                <label className="text-[10px] font-bold text-slate-500 uppercase tracking-widest">Επιλέξτε Έργο Γάμου</label>
                <div className="relative">
                  <select 
                    value={selectedProjectId}
                    onChange={(e) => setSelectedProjectId(e.target.value)}
                    className="w-full glass-dark p-5 rounded-2xl appearance-none outline-none focus:ring-2 focus:ring-indigo-500/50 pr-12 font-bold text-lg"
                  >
                    {projects.map(p => (
                      <option key={p.id} value={p.id}>{p.coupleNames} ({new Date(p.weddingDate).getFullYear()})</option>
                    ))}
                  </select>
                  <ChevronDown className="absolute right-4 top-1/2 -translate-y-1/2 text-slate-500 pointer-events-none" size={24} />
                </div>
              </div>
            </div>

            <div className="space-y-8">
              <div className="flex items-center gap-4 p-4 md:p-0">
                <div className="w-14 h-14 rounded-2xl bg-indigo-500/20 flex items-center justify-center text-3xl border border-indigo-500/30 shrink-0">
                  {selectedModule.icon}
                </div>
                <div>
                  <h3 className="text-xl font-bold font-serif">{selectedModule.title}</h3>
                  <p className="text-slate-500 text-sm leading-tight">{selectedModule.description}</p>
                </div>
              </div>

              <div className="grid grid-cols-1 gap-5">
                {selectedModule.inputs.map(input => (
                  <div key={input.key} className="space-y-3">
                    <label className="text-sm font-bold text-slate-400 uppercase tracking-tight">{input.label}</label>
                    {input.type === 'textarea' ? (
                      <textarea
                        value={inputs[input.key] || ''}
                        onChange={e => setInputs({...inputs, [input.key]: e.target.value})}
                        className="w-full glass-dark p-5 rounded-2xl min-h-[120px] outline-none focus:ring-2 focus:ring-indigo-500/40 text-base"
                        placeholder="Προσθέστε συγκεκριμένες λεπτομέρειες για να καθοδηγήσετε το AI..."
                      />
                    ) : input.type === 'select' ? (
                      <select
                        value={inputs[input.key] || ''}
                        onChange={e => setInputs({...inputs, [input.key]: e.target.value})}
                        className="w-full glass-dark p-5 rounded-2xl outline-none focus:ring-2 focus:ring-indigo-500/40 text-base appearance-none"
                      >
                        <option value="">Επιλέξτε...</option>
                        {input.options?.map(opt => <option key={opt} value={opt}>{opt}</option>)}
                      </select>
                    ) : (
                      <input
                        type="text"
                        value={inputs[input.key] || ''}
                        onChange={e => setInputs({...inputs, [input.key]: e.target.value})}
                        className="w-full glass-dark p-5 rounded-2xl outline-none focus:ring-2 focus:ring-indigo-500/40 text-base"
                        placeholder="Πληκτρολογήστε εδώ..."
                      />
                    )}
                  </div>
                ))}
              </div>

              <button 
                onClick={handleGenerate}
                disabled={isGenerating || !selectedProjectId}
                className="w-full py-5 rounded-2xl bg-gradient-to-r from-indigo-600 to-purple-600 hover:from-indigo-500 hover:to-purple-500 text-white font-bold flex items-center justify-center gap-3 transition-all disabled:opacity-50 disabled:cursor-not-allowed shadow-2xl shadow-indigo-600/20 text-lg"
              >
                {isGenerating ? (
                  <>
                    <Loader2 className="animate-spin" size={24} />
                    Δημιουργία Μαγείας...
                  </>
                ) : (
                  <>
                    <Sparkles size={24} />
                    Παραγωγή Περιεχομένου
                  </>
                )}
              </button>
            </div>
          </div>

          {result && (
            <div className="glass p-6 md:p-8 rounded-3xl space-y-6 animate-in slide-in-from-bottom-4">
              <div className="flex flex-col sm:flex-row items-center justify-between border-b border-slate-800 pb-5 gap-4">
                <h4 className="text-lg font-bold flex items-center gap-2"><Check className="text-emerald-400" /> Αποτέλεσμα AI</h4>
                <button onClick={handleSave} className="w-full sm:w-auto flex items-center justify-center gap-2 px-6 py-3 bg-emerald-600/20 text-emerald-400 border-2 border-emerald-500/30 rounded-xl hover:bg-emerald-600 transition-all hover:text-white font-bold">
                  <Save size={20} /> Αποθήκευση
                </button>
              </div>
              <div className="prose prose-invert max-w-none text-slate-300 whitespace-pre-wrap leading-relaxed text-base">
                {result}
              </div>
            </div>
          )}
        </div>

        {/* History / Saved */}
        <div className="lg:col-span-3 space-y-6">
          <div className="glass p-6 rounded-3xl space-y-6">
            <h3 className="text-lg font-bold font-serif flex items-center gap-2 uppercase tracking-tight"><History size={22} className="text-sky-400" /> Πρόσφατα</h3>
            <div className="space-y-4">
              {savedResults.length === 0 ? (
                <p className="text-xs text-slate-500 text-center py-10 italic">Δεν υπάρχουν αποθηκευμένα αποτελέσματα.</p>
              ) : (
                savedResults.filter(r => r.projectId === selectedProjectId).map(result => (
                  <div key={result.id} className="group glass-dark p-4 rounded-xl border border-slate-800 hover:border-slate-600 transition-all">
                    <div className="flex items-start justify-between mb-3">
                      <div className="flex-1 min-w-0">
                        <p className="text-[9px] font-bold text-indigo-400 uppercase tracking-widest mb-1 truncate">{result.moduleType.replace('-', ' ')}</p>
                        <p className="text-xs font-bold text-white">{new Date(result.createdAt).toLocaleDateString('el-GR')}</p>
                      </div>
                      <button 
                        onClick={() => setSavedResults(savedResults.filter(r => r.id !== result.id))}
                        className="text-slate-600 hover:text-rose-400 p-1 opacity-0 group-hover:opacity-100 transition-opacity"
                      >
                        <Trash2 size={16} />
                      </button>
                    </div>
                    <button 
                      onClick={() => setResult(result.content)}
                      className="w-full py-2 bg-slate-800 rounded-lg text-[10px] font-bold uppercase text-slate-400 flex items-center justify-center gap-2 hover:bg-slate-700 hover:text-white transition-all"
                    >
                      <ExternalLink size={12} /> Προβολή
                    </button>
                  </div>
                ))
              )}
            </div>
          </div>
        </div>
      </div>
    </div>
  );
};

