                      className="w-16 h-16 rounded-2xl cursor-pointer bg-transparent border-0"
                    />
                    <input type="text" value={localProfile.brandColors.secondary} className="flex-1 glass-dark p-4 rounded-xl text-sm font-mono" readOnly />
