                    <input 
                      type="color" 
                      value={localProfile.brandColors.accent} 
                      onChange={e => setLocalProfile({...localProfile, brandColors: {...localProfile.brandColors, accent: e.target.value}})}
                      className="w-16 h-16 rounded-2xl cursor-pointer bg-transparent border-0"
                    />
                    <input type="text" value={localProfile.brandColors.accent} className="flex-1 glass-dark p-4 rounded-xl text-sm font-mono" readOnly />
                  </div>
                </div>
              </div>

              <div className="p-10 rounded-3xl border-2 border-dashed border-slate-700 bg-slate-900/50 flex flex-col items-center justify-center space-y-6">
                <div className="w-24 h-24 rounded-3xl bg-slate-800 flex items-center justify-center text-slate-600 shadow-inner">
                  <Palette size={48} />
                </div>
                <div className="text-center">
                  <p className="font-bold text-xl mb-1 font-serif">Λογότυπο Studio</p>
                  <p className="text-sm text-slate-500 uppercase tracking-widest">Προτεινόμενο 512x512px (SVG ή PNG)</p>
                </div>
                <button className="px-10 py-4 bg-indigo-600/20 text-indigo-400 border-2 border-indigo-500/30 rounded-2xl text-sm font-bold hover:bg-indigo-600 hover:text-white transition-all uppercase tracking-widest">
                  Μεταφόρτωση Logo
                </button>
              </div>
            </div>
          )}

          {activeTab === 'contracts' && (
            <div className="space-y-6 animate-in slide-in-from-left-4">
              <div className="space-y-4">
                <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center gap-2 mb-2">
                  <label className="text-[10px] font-bold text-slate-500 uppercase flex items-center gap-2 tracking-widest"><FileText size={14}/> Συμφωνητικό Παροχής Υπηρεσιών</label>
                  <span className="text-[10px] text-slate-600 italic">Υποστηρίζει μορφοποίηση Markdown</span>
                </div>
                <textarea 
                  value={localProfile.contractTemplate} 
                  onChange={e => setLocalProfile({...localProfile, contractTemplate: e.target.value})}
                  className="w-full glass-dark p-8 rounded-3xl min-h-[450px] outline-none focus:ring-2 focus:ring-indigo-500/30 font-mono text-sm leading-relaxed border border-slate-800"
                  placeholder="Εισάγετε τους όρους του συμβολαίου σας εδώ..."
