      <div className="bg-rose-500/10 border-2 border-rose-500/30 p-6 rounded-3xl flex flex-col sm:flex-row items-center sm:items-start gap-4 text-center sm:text-left">
        <Shield className="text-rose-400 shrink-0" size={32} />
        <div>
          <h4 className="font-bold text-rose-400 mb-2 uppercase tracking-widest">Ασφάλεια Δεδομένων & API</h4>
          <p className="text-sm text-slate-400 leading-relaxed">Τα αιτήματα του AI Studio τροφοδοτούνται από το Google Gemini. Όλα τα δεδομένα του έργου αποθηκεύονται τοπικά στο πρόγραμμα περιήγησής σας (Local Storage) για αυτή την έκδοση. Σε περιβάλλον παραγωγής, η Row Level Security (RLS) διασφαλίζει ότι μόνο εσείς έχετε πρόσβαση στα έργα σας.</p>
        </div>
      </div>
    </div>
  );
};

export default Settings;

import React, { useState } from 'react';
import { Project, AIModuleType, Deliverables } from '../types';
import { 
  ArrowLeft, Edit2, Trash2, Mail, Phone, ExternalLink, 
  Clock, CheckCircle, Wallet, ListChecks, Sparkles, 
  ChevronRight, Save, X, Calendar, MapPin, FileText
} from 'lucide-react';
import { STATUS_COLORS, AI_MODULES, STATUS_LABELS } from '../constants';

interface ProjectDetailProps {
  project: Project;
  onUpdateProject: (p: Project) => void;
  onDeleteProject: (id: string) => void;
  onBack: () => void;
  onNavigateAI: (moduleId: AIModuleType) => void;
}

const ProjectDetail: React.FC<ProjectDetailProps> = ({ 
  project, onUpdateProject, onDeleteProject, onBack, onNavigateAI 
}) => {
  const [isEditing, setIsEditing] = useState(false);
  const [editedProject, setEditedProject] = useState<Project>(project);

  const handleSave = () => {
    onUpdateProject(editedProject);
    setIsEditing(false);
  };

  // Fixed: Use explicit Deliverables key type for safety
  const toggleDeliverable = (key: keyof Deliverables) => {
    const updated = {
      ...project,
      deliverables: { ...project.deliverables, [key]: !project.deliverables[key] }
    };
    onUpdateProject(updated);
  };

  const togglePayment = (key: 'depositPaid' | 'balancePaid') => {
    const updated = {
      ...project,
      payments: { ...project.payments, [key]: !project.payments[key] }
    };
    onUpdateProject(updated);
  };

  const getDaysRemaining = () => {
    const diff = new Date(project.weddingDate).getTime() - Date.now();
    return Math.ceil(diff / (1000 * 60 * 60 * 24));
  };

  // Fixed: Added explicit Record type to handle key indexing safely
  const deliverableLabels: Record<keyof Deliverables, string> = {
    highlightFilm: 'Highlight Film',
    fullFilm: 'Πλήρης Ταινία',
    socialMediaContent: 'Content για Social',
    usbBox: 'USB Box',
    onlineLink: 'Online Σύνδεσμος'
  };

  return (
    <div className="space-y-8 animate-in slide-in-from-right-4 duration-500">
      <div className="flex items-center justify-between gap-4">
        <button onClick={onBack} className="flex items-center gap-2 text-slate-400 hover:text-white transition-colors py-2">
          <ArrowLeft size={20} />
          <span className="hidden sm:inline">Επιστροφή στα Έργα</span>
          <span className="sm:hidden">Πίσω</span>
        </button>
        <div className="flex gap-2">
          {isEditing ? (
            <>
              <button onClick={handleSave} className="flex items-center gap-2 bg-emerald-600 hover:bg-emerald-500 px-4 py-3 rounded-xl font-bold transition-all shadow-lg shadow-emerald-600/20">
                <Save size={18} /> <span className="hidden sm:inline">Αποθήκευση</span>
              </button>
              <button onClick={() => setIsEditing(false)} className="flex items-center gap-2 bg-slate-700 hover:bg-slate-600 px-4 py-3 rounded-xl font-bold transition-all text-slate-200">
                <X size={18} /> <span className="hidden sm:inline">Ακύρωση</span>
              </button>
            </>
          ) : (
            <>
              <button onClick={() => setIsEditing(true)} className="p-3 glass text-slate-400 hover:text-white rounded-xl transition-colors">
                <Edit2 size={20} />
              </button>
              <button onClick={() => onDeleteProject(project.id)} className="p-3 glass text-slate-400 hover:text-rose-400 rounded-xl transition-colors">
                <Trash2 size={20} />
              </button>
            </>
          )}
        </div>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
        {/* Left Column: Info & Status */}
        <div className="lg:col-span-2 space-y-6">
          <section className="glass p-6 md:p-8 rounded-3xl relative overflow-hidden">
            <div className="absolute top-0 right-0 w-32 h-32 bg-indigo-600/10 blur-3xl -mr-16 -mt-16"></div>
            <div className="flex flex-col md:flex-row md:items-end justify-between gap-6">
              <div className="flex-1 min-w-0">
                <span className={`px-3 py-1 rounded-lg text-[10px] font-bold tracking-widest border ${STATUS_COLORS[project.status]} inline-block mb-4`}>
                  {STATUS_LABELS[project.status as keyof typeof STATUS_LABELS]}
                </span>
                {isEditing ? (
                  <input 
                    className="text-3xl md:text-4xl font-bold font-serif bg-slate-800 rounded-xl px-4 py-2 w-full focus:ring-2 focus:ring-indigo-500/50 outline-none" 
                    value={editedProject.coupleNames} 
                    onChange={e => setEditedProject({...editedProject, coupleNames: e.target.value})}
                  />
                ) : (
                  <h2 className="text-3xl md:text-4xl font-bold font-serif truncate">{project.coupleNames}</h2>
                )}
                <div className="flex flex-wrap items-center gap-4 mt-6 text-slate-400 text-sm">
                  <span className="flex items-center gap-2"><Calendar size={18} className="text-indigo-400" /> {new Date(project.weddingDate).toLocaleDateString('el-GR')}</span>
                  <span className="flex items-center gap-2"><MapPin size={18} className="text-indigo-400" /> {project.location}</span>
                </div>
              </div>
              <div className="bg-slate-900/50 p-5 rounded-2xl border border-slate-800 w-full md:w-auto text-center md:text-left">
                <div className="text-[10px] text-slate-500 font-bold uppercase tracking-widest mb-1">Αντίστροφη Μέτρηση</div>
                <div className="text-4xl font-bold flex items-baseline justify-center md:justify-start gap-1">
                  {getDaysRemaining()} <span className="text-xs font-normal text-slate-400 uppercase">μέρες</span>
                </div>
              </div>
            </div>
          </section>

          <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
            {/* Contact Card */}
            <div className="glass p-6 rounded-3xl space-y-5">
              <h3 className="text-lg font-bold flex items-center gap-2 font-serif uppercase tracking-tight"><Phone size={20} className="text-indigo-400" /> Επικοινωνία Πελάτη</h3>
              <div className="space-y-3">
                <div className="flex items-center justify-between p-4 rounded-2xl bg-slate-900/30 border border-slate-800">
                  <div className="flex items-center gap-3 min-w-0">
                    <Mail size={16} className="text-slate-500 shrink-0" />
                    <span className="text-sm truncate">{project.contact.email}</span>
                  </div>
                  <a href={`mailto:${project.contact.email}`} className="text-indigo-400 hover:text-indigo-300 p-1"><ExternalLink size={18} /></a>
                </div>
                <div className="flex items-center justify-between p-4 rounded-2xl bg-slate-900/30 border border-slate-800">
                  <div className="flex items-center gap-3 min-w-0">
                    <Phone size={16} className="text-slate-500 shrink-0" />
                    <span className="text-sm truncate">{project.contact.phone}</span>
                  </div>
                  <a href={`tel:${project.contact.phone}`} className="text-indigo-400 hover:text-indigo-300 p-1"><ExternalLink size={18} /></a>
                </div>
              </div>
            </div>

            {/* Payment Tracking */}
            <div className="glass p-6 rounded-3xl space-y-5">
              <h3 className="text-lg font-bold flex items-center gap-2 font-serif uppercase tracking-tight"><Wallet size={20} className="text-emerald-400" /> Οικονομικά</h3>
              <div className="space-y-3">
                <div className="p-5 rounded-2xl bg-slate-900/30 border border-slate-800">
                  <div className="flex justify-between items-center mb-2">
                    <span className="text-[10px] text-slate-500 font-bold uppercase tracking-wider">{project.payments.packageName}</span>
                    <span className="text-xl font-bold">€{project.payments.totalAmount}</span>
                  </div>
                  <div className="flex gap-6 mt-4">
                    <button 
                      onClick={() => togglePayment('depositPaid')}
                      className="flex items-center gap-3 cursor-pointer group"
                    >
                      <div className={`w-6 h-6 rounded-lg flex items-center justify-center border-2 transition-all ${project.payments.depositPaid ? 'bg-emerald-500 border-emerald-500 shadow-lg shadow-emerald-500/20' : 'border-slate-700'}`}>
                        {project.payments.depositPaid && <CheckCircle size={16} className="text-white" />}
                      </div>
                      <span className={`text-xs font-bold uppercase tracking-wider ${project.payments.depositPaid ? 'text-emerald-400' : 'text-slate-500'}`}>Προκαταβολή</span>
                    </button>
                    <button 
                      onClick={() => togglePayment('balancePaid')}
                      className="flex items-center gap-3 cursor-pointer group"
                    >
                      <div className={`w-6 h-6 rounded-lg flex items-center justify-center border-2 transition-all ${project.payments.balancePaid ? 'bg-emerald-500 border-emerald-500 shadow-lg shadow-emerald-500/20' : 'border-slate-700'}`}>
                        {project.payments.balancePaid && <CheckCircle size={16} className="text-white" />}
                      </div>
                      <span className={`text-xs font-bold uppercase tracking-wider ${project.payments.balancePaid ? 'text-emerald-400' : 'text-slate-500'}`}>Εξόφληση</span>
                    </button>
                  </div>
                </div>
              </div>
            </div>
          </div>

          {/* AI Tools Access */}
          <section className="space-y-5">
            <h3 className="text-xl font-bold font-serif flex items-center gap-3 uppercase tracking-tight"><Sparkles className="text-purple-400" size={26} /> AI Studio Modules</h3>
            <div className="grid grid-cols-2 sm:grid-cols-4 gap-3 md:gap-4">
              {AI_MODULES.slice(0, 8).map(module => (
                <button
                  key={module.id}
                  onClick={() => onNavigateAI(module.id)}
                  className="glass-dark p-5 rounded-2xl flex flex-col items-center gap-3 hover:bg-slate-700/40 transition-all border border-slate-800/50 hover:border-indigo-500/30"
                >
                  <span className="text-4xl">{module.icon}</span>
                  <span className="text-[10px] font-bold text-center uppercase tracking-tight text-slate-400 group-hover:text-white">{module.title}</span>
                </button>
              ))}
            </div>
          </section>
        </div>

        {/* Right Column: Checklist & Notes */}
        <div className="space-y-6">
          <section className="glass p-6 rounded-3xl space-y-6">
            <h3 className="text-lg font-bold flex items-center gap-2 font-serif uppercase tracking-tight"><ListChecks size={22} className="text-sky-400" /> Παραδοτέα</h3>
            <div className="space-y-3">
              {/* Fixed: Use explicit casting for Object.keys to keyof Deliverables to resolve TS error at toggleDeliverable call */}
              {(Object.keys(project.deliverables) as (keyof Deliverables)[]).map((deliverableKey) => {
                return (
                  <button 
                    key={String(deliverableKey)}
                    onClick={() => toggleDeliverable(deliverableKey)}
                    className={`w-full flex items-center justify-between p-4 rounded-2xl border-2 transition-all ${project.deliverables[deliverableKey] ? 'bg-indigo-500/10 border-indigo-500/40 text-indigo-400' : 'bg-slate-900/30 border-slate-800 text-slate-500 hover:border-slate-700'}`}
                  >
                    <span className="text-sm font-bold uppercase tracking-tight">{deliverableLabels[deliverableKey] || String(deliverableKey)}</span>
                    {project.deliverables[deliverableKey] ? <CheckCircle size={22} className="fill-indigo-500 text-[#0f172a]" /> : <div className="w-5 h-5 rounded-full border-2 border-slate-700"></div>}
                  </button>
                );
              })}
            </div>
          </section>

          <section className="glass p-6 rounded-3xl space-y-4">
            <h3 className="text-lg font-bold flex items-center gap-2 font-serif uppercase tracking-tight"><FileText size={22} className="text-amber-400" /> Σημειώσεις Έργου</h3>
            <textarea 
              className="w-full glass-dark p-5 rounded-2xl min-h-[150px] text-sm text-slate-300 outline-none focus:ring-2 focus:ring-amber-500/30 border border-slate-800"
              placeholder="Προσθέστε σημαντικές λεπτομέρειες για τον εξοπλισμό, την τοποθεσία ή ειδικές επιθυμίες του ζευγαριού..."
              value={project.notes}
              onChange={(e) => onUpdateProject({...project, notes: e.target.value})}
            ></textarea>
          </section>
        </div>
      </div>
    </div>
  );
};

export default ProjectDetail;
